import { useTranslation } from "react-i18next";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Users, Store, Calendar, MessageSquare, FileText, Utensils, Clock } from "lucide-react";

interface DashboardStatsCardsProps {
  stats: {
    totalUsers?: number;
    totalRestaurants?: number;
    totalActivities?: number;
    totalComments?: number;
    totalPosts?: number;
    totalRecipes?: number;
    pendingPosts?: number;
  } | undefined;
  isSupervisor: boolean;
}

const DashboardStatsCards = ({ stats, isSupervisor }: DashboardStatsCardsProps) => {
  const { t } = useTranslation();

  return (
    <>
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              {isSupervisor ? t("admin.managedMerchants") : t("admin.totalUsers")}
            </CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.totalUsers || 0}</div>
            <p className="text-xs text-muted-foreground">
              {isSupervisor ? t("admin.managedMerchantsDesc") : t("admin.registeredUsers")}
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              {isSupervisor ? t("admin.managedRestaurants") : t("admin.totalRestaurants")}
            </CardTitle>
            <Store className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.totalRestaurants || 0}</div>
            <p className="text-xs text-muted-foreground">
              {isSupervisor ? t("admin.managedRestaurantsDesc") : t("admin.listedRestaurants")}
            </p>
          </CardContent>
        </Card>

        {!isSupervisor && (
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">{t("admin.totalActivities")}</CardTitle>
              <Calendar className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats?.totalActivities || 0}</div>
              <p className="text-xs text-muted-foreground">{t("admin.activeEvents")}</p>
            </CardContent>
          </Card>
        )}

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              {isSupervisor ? t("admin.restaurantComments") : t("admin.totalComments")}
            </CardTitle>
            <MessageSquare className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.totalComments || 0}</div>
            <p className="text-xs text-muted-foreground">
              {isSupervisor ? t("admin.restaurantCommentsDesc") : t("admin.userReviews")}
            </p>
          </CardContent>
        </Card>
      </div>

      {!isSupervisor && (
        <div className="grid gap-4 md:grid-cols-3">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">{t("admin.totalPosts")}</CardTitle>
              <FileText className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats?.totalPosts || 0}</div>
              <p className="text-xs text-muted-foreground">{t("admin.approvedPosts")}</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">{t("admin.totalRecipes")}</CardTitle>
              <Utensils className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats?.totalRecipes || 0}</div>
              <p className="text-xs text-muted-foreground">{t("admin.publishedRecipes")}</p>
            </CardContent>
          </Card>

          <Card className={stats?.pendingPosts ? "border-yellow-500/50" : ""}>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">{t("admin.pendingPosts")}</CardTitle>
              <Clock className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats?.pendingPosts || 0}</div>
              <p className="text-xs text-muted-foreground">{t("admin.awaitingReview")}</p>
            </CardContent>
          </Card>
        </div>
      )}
    </>
  );
};

export default DashboardStatsCards;
