import { useTranslation } from "react-i18next";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { TrendingUp, BarChart3, UserPlus, Forward, Star } from "lucide-react";
import {
  LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
} from "recharts";

// Generate distinct colors for chart series
const CHART_COLORS = [
  "hsl(160, 70%, 40%)",  // teal
  "hsl(220, 70%, 55%)",  // blue
  "hsl(35, 85%, 55%)",   // amber
  "hsl(340, 70%, 55%)",  // rose
  "hsl(270, 60%, 55%)",  // purple
  "hsl(100, 60%, 45%)",  // green
  "hsl(190, 70%, 45%)",  // cyan
  "hsl(15, 80%, 55%)",   // orange
  "hsl(300, 50%, 50%)",  // magenta
  "hsl(50, 80%, 50%)",   // yellow
];

const getColor = (index: number) => CHART_COLORS[index % CHART_COLORS.length];

// Truncate long labels
const truncateLabel = (label: string, maxLen = 12) =>
  label.length > maxLen ? label.slice(0, maxLen) + "…" : label;

interface DashboardChartsProps {
  ratingTrends: Record<string, unknown>[] | undefined;
  commentTrends: Record<string, unknown>[] | undefined;
  activityEngagement: Array<{ name: string; subscribers: number; comments: number }> | undefined;
  shareTrends: Record<string, unknown>[] | undefined;
  shareStats: Array<{ name: string; shares: number }> | undefined;
  topRestaurants: Array<{ name: string; rating: number; comments: number }> | undefined;
  isSupervisor: boolean;
}

const DashboardCharts = ({
  ratingTrends,
  commentTrends,
  activityEngagement,
  shareTrends,
  shareStats,
  topRestaurants,
  isSupervisor,
}: DashboardChartsProps) => {
  const { t } = useTranslation();

  return (
    <>
      <div className="grid gap-4 md:grid-cols-2">
        {/* Restaurant Rating Trends */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <TrendingUp className="h-4 w-4" />
              {t("admin.restaurantRatingTrends")}
            </CardTitle>
            <CardDescription className="text-xs">
              {isSupervisor ? t("admin.restaurantRatingTrendsDescSupervisor") : t("admin.restaurantRatingTrendsDescAdmin")}
            </CardDescription>
          </CardHeader>
          <CardContent>
            {ratingTrends && ratingTrends.length > 0 ? (
              <ResponsiveContainer width="100%" height={280}>
                <LineChart data={ratingTrends}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="month" tick={{ fontSize: 11 }} />
                  <YAxis domain={[0, 5]} tick={{ fontSize: 11 }} />
                  <Tooltip contentStyle={{ fontSize: 12, borderRadius: 8 }} />
                  <Legend wrapperStyle={{ fontSize: 11 }} />
                  {Object.keys(ratingTrends[0])
                    .filter(key => key !== "month")
                    .map((name, i) => (
                      <Line key={name} type="monotone" dataKey={name} stroke={getColor(i)} strokeWidth={2} dot={{ r: 3 }} />
                    ))}
                </LineChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-[280px] flex items-center justify-center text-muted-foreground text-sm">
                {t("admin.noRatingData")}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Restaurant Comment Trends */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <BarChart3 className="h-4 w-4" />
              {t("admin.restaurantCommentTrends")}
            </CardTitle>
            <CardDescription className="text-xs">
              {isSupervisor ? t("admin.restaurantCommentTrendsDescSupervisor") : t("admin.restaurantCommentTrendsDescAdmin")}
            </CardDescription>
          </CardHeader>
          <CardContent>
            {commentTrends && commentTrends.length > 0 ? (
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={commentTrends}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="month" tick={{ fontSize: 11 }} />
                  <YAxis tick={{ fontSize: 11 }} />
                  <Tooltip contentStyle={{ fontSize: 12, borderRadius: 8 }} />
                  <Legend wrapperStyle={{ fontSize: 11 }} />
                  {Object.keys(commentTrends[0])
                    .filter(key => key !== "month")
                    .map((name, i) => (
                      <Bar key={name} dataKey={name} fill={getColor(i)} radius={[2, 2, 0, 0]} />
                    ))}
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-[280px] flex items-center justify-center text-muted-foreground text-sm">
                {t("admin.noCommentData")}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Activity Engagement - Admins only */}
        {!isSupervisor && activityEngagement && activityEngagement.length > 0 && (
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-base">
                <UserPlus className="h-4 w-4" />
                {t("admin.activityEngagement")}
              </CardTitle>
              <CardDescription className="text-xs">{t("admin.activityEngagementDescription")}</CardDescription>
            </CardHeader>
            <CardContent>
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={activityEngagement}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis
                    dataKey="name"
                    tick={{ fontSize: 10 }}
                    interval={0}
                    tickFormatter={(v) => truncateLabel(v, 10)}
                    height={60}
                    angle={-35}
                    textAnchor="end"
                  />
                  <YAxis tick={{ fontSize: 11 }} />
                  <Tooltip contentStyle={{ fontSize: 12, borderRadius: 8 }} />
                  <Legend wrapperStyle={{ fontSize: 11 }} />
                  <Bar dataKey="subscribers" name={t("admin.subscribers")} fill={getColor(0)} radius={[2, 2, 0, 0]} />
                  <Bar dataKey="comments" name={t("admin.comments")} fill={getColor(1)} radius={[2, 2, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>
        )}

        {/* Activity Share Stats - Admins only */}
        {!isSupervisor && (
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-base">
                <Forward className="h-4 w-4" />
                {t("admin.activityShareRanking")}
              </CardTitle>
              <CardDescription className="text-xs">{t("admin.activityShareRankingDesc")}</CardDescription>
            </CardHeader>
            <CardContent>
              {shareStats && shareStats.length > 0 ? (
                <ResponsiveContainer width="100%" height={280}>
                  <BarChart data={shareStats} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis type="number" tick={{ fontSize: 11 }} />
                    <YAxis
                      dataKey="name"
                      type="category"
                      width={100}
                      tick={{ fontSize: 10 }}
                      tickFormatter={(v) => truncateLabel(v, 14)}
                    />
                    <Tooltip contentStyle={{ fontSize: 12, borderRadius: 8 }} />
                    <Bar dataKey="shares" name={t("admin.shareCount")} fill={getColor(0)} radius={[0, 2, 2, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-[280px] flex items-center justify-center text-muted-foreground text-sm">
                  {t("admin.noShareData")}
                </div>
              )}
            </CardContent>
          </Card>
        )}

        {/* Activity Share Trends - Admins only */}
        {!isSupervisor && shareTrends && shareTrends.length > 0 && (
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-base">
                <TrendingUp className="h-4 w-4" />
                {t("admin.activityShareTrends")}
              </CardTitle>
              <CardDescription className="text-xs">{t("admin.activityShareTrendsDesc")}</CardDescription>
            </CardHeader>
            <CardContent>
              <ResponsiveContainer width="100%" height={280}>
                <LineChart data={shareTrends}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="month" tick={{ fontSize: 11 }} />
                  <YAxis tick={{ fontSize: 11 }} />
                  <Tooltip contentStyle={{ fontSize: 12, borderRadius: 8 }} />
                  <Legend wrapperStyle={{ fontSize: 11 }} />
                  {Object.keys(shareTrends[0])
                    .filter(key => key !== "month")
                    .map((name, i) => (
                      <Line key={name} type="monotone" dataKey={name} stroke={getColor(i)} strokeWidth={2} dot={{ r: 3 }} />
                    ))}
                </LineChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Top Restaurants */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-base">
            <Star className="h-4 w-4" />
            {isSupervisor ? t("admin.topRestaurantsRanking") : t("admin.topRestaurants")}
          </CardTitle>
          <CardDescription className="text-xs">
            {isSupervisor ? t("admin.topRestaurantsRankingDescSupervisor") : t("admin.topRestaurantsDescription")}
          </CardDescription>
        </CardHeader>
        <CardContent>
          {topRestaurants && topRestaurants.length > 0 ? (
            <ResponsiveContainer width="100%" height={350}>
              <BarChart data={topRestaurants} layout="horizontal">
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis type="number" tick={{ fontSize: 11 }} />
                <YAxis
                  dataKey="name"
                  type="category"
                  width={140}
                  tick={{ fontSize: 11 }}
                  tickFormatter={(v) => truncateLabel(v, 18)}
                />
                <Tooltip contentStyle={{ fontSize: 12, borderRadius: 8 }} />
                <Legend wrapperStyle={{ fontSize: 11 }} />
                <Bar dataKey="rating" name={t("admin.rating")} fill={getColor(0)} radius={[0, 2, 2, 0]} />
                <Bar dataKey="comments" name={t("admin.comments")} fill={getColor(1)} radius={[0, 2, 2, 0]} />
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div className="h-[350px] flex items-center justify-center text-muted-foreground text-sm">
              {isSupervisor ? t("admin.noAssignedRestaurants") : t("admin.noData")}
            </div>
          )}
        </CardContent>
      </Card>
    </>
  );
};

export default DashboardCharts;
