import { useTranslation } from "react-i18next";
import { 
  useAdminStats, 
  useTopRestaurants, 
  useActivityEngagement,
  useRestaurantRatingTrends,
  useRestaurantCommentTrends,
  useActivityShareTrends,
  useActivityShareStats
} from "@/hooks/useAdmin";
import { useUserRole } from "@/hooks/useUserRole";
import DashboardStatsCards from "./components/DashboardStatsCards";
import DashboardCharts from "./components/DashboardCharts";

const AdminDashboard = () => {
  const { t } = useTranslation();
  const { isSupervisor } = useUserRole();
  const { data: stats, isLoading } = useAdminStats();
  const { data: topRestaurants } = useTopRestaurants();
  const { data: activityEngagement } = useActivityEngagement();
  const { data: ratingTrends } = useRestaurantRatingTrends();
  const { data: commentTrends } = useRestaurantCommentTrends();
  const { data: shareTrends } = useActivityShareTrends();
  const { data: shareStats } = useActivityShareStats();

  if (isLoading) {
    return <div className="text-center">{t("common.loading")}</div>;
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold mb-2">{t("admin.dashboard")}</h1>
        <p className="text-muted-foreground">{t("admin.dashboardDescription")}</p>
      </div>

      <DashboardStatsCards stats={stats} isSupervisor={isSupervisor} />

      <DashboardCharts
        ratingTrends={ratingTrends}
        commentTrends={commentTrends}
        activityEngagement={activityEngagement}
        shareTrends={shareTrends}
        shareStats={shareStats}
        topRestaurants={topRestaurants}
        isSupervisor={isSupervisor}
      />
    </div>
  );
};

export default AdminDashboard;
